public class XSSProtection {

    public static void main(String[] args) {
        // Simulating user input from a form
        String userInput = "<script>alert('XSS Attack!');</script>";

        // Sanitize user input by escaping special HTML characters
        String sanitizedInput = escapeHtml(userInput);

        // Display sanitized user input on a webpage
        String output = "<p>Welcome, " + sanitizedInput + "</p>";
        System.out.println(output);
    }

    public static String escapeHtml(String input) {
        return input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
